import org.xml.sax.*;
import javax.xml.parsers.*;
public class java_49060_XMLParser_A07 {  
    public static void main(String[] args) throws ParserConfigurationException, SAXException{        
        String url = "path_to_yourfile";  // replace with actual path to your xml file here            
          XmlPullParserFactory factory = 
            XmlPullParserFactory.newInstance();   
           XMLReader reader=factory.newSAXParser().getXmlReader(url,1024*10);   /*buffer size is 1024 * 10*/    
          MyContentHandler handler = new MyContentHandler();      
         //Setting the Content Handler to SAX parser   
            reader.setContentHandler(handler);     
           while (reader.hasNext()) {            
              reader.next();              
          }  
        System.out.println("XML Parsing completed."); 
     }      
}        
